#include <iostream>

class Int17Matrix3D {
public:

  Int17Matrix3D(int x, int y, int z);

  Int17Matrix3D(const Int17Matrix3D& other);

  ~Int17Matrix3D();

  Int17Matrix3D& operator=(int32_t value);  

  Int17Matrix3D& operator=(const Int17Matrix3D& other);

  static Int17Matrix3D make_array(int x, int y, int z);

  void copy(int32_t* array1, const int32_t* array2, int size);

  void SetValueAtCurrentIndex(int32_t value);

  class Proxy3D;
  class Proxy2D;
  class Proxy1D;

  Proxy2D operator[](int x);

  void SetValueAtIndex(int x, int y, int z, int32_t value);
  int32_t GetValueAtIndex(int x, int y, int z) const;

  Int17Matrix3D operator+(const Int17Matrix3D& other);

  Int17Matrix3D operator-(const Int17Matrix3D& other);

  Int17Matrix3D operator*(int32_t mult);

private:
  const int8_t kNumLenght_ = 17;
  int32_t current_index_;
  int32_t max_index_;
  int32_t width_;
  int32_t height_;
  int32_t depth_;
  int32_t* array_;
  int32_t current_x_ = 0;
  int32_t current_y_ = 0;
  int32_t current_z_ = 0;

  bool TakeBit(const int32_t* value, uint32_t bit_position) const;

  Int17Matrix3D& ClearBit(int32_t* value, int32_t bit_position);

  Int17Matrix3D& SetBit(int32_t* value, int32_t bit_position);

  int GetIndex(int x, int y, int z) const;

  int32_t ToDecimal(const int32_t* array_, int32_t current_index_) const;

  friend std::ostream& operator<<(std::ostream& stream, const Int17Matrix3D& array);

  friend std::istream& operator>>(std::istream& stream, const Int17Matrix3D& array);

  friend bool operator==(const Int17Matrix3D& lhs, const Int17Matrix3D& rhs);

  friend bool operator!=(const Int17Matrix3D& lhs, const Int17Matrix3D& rhs);
};

class Int17Matrix3D::Proxy3D {
    Int17Matrix3D& parentMatrix_;
    int x_, y_, z_;

public:
    Proxy3D(Int17Matrix3D& parentMatrix_, int x, int y, int z)
        : parentMatrix_(parentMatrix_), x_(x), y_(y), z_(z) {}

    Proxy3D& operator=(int value) {
        parentMatrix_.SetValueAtIndex(x_, y_, z_, value);
        return *this;
    }

    operator int() const {
        return parentMatrix_.GetValueAtIndex(x_, y_, z_);
    }
};

class Int17Matrix3D::Proxy2D {
  Int17Matrix3D& parentMatrix_;
  int x_;

public:
  Proxy2D(Int17Matrix3D& parentMatrix_, int x) : parentMatrix_(parentMatrix_), x_(x) {}

  Proxy1D operator[](int y);
};

class Int17Matrix3D::Proxy1D {
  Int17Matrix3D& parentMatrix_;
  int x_, y_;

public:
  Proxy1D(Int17Matrix3D& parentMatrix_, int x, int y) : parentMatrix_(parentMatrix_), x_(x), y_(y) {}
  Proxy3D operator[](int z) {
        return Proxy3D(parentMatrix_, x_, y_, z);
    }
};


