#include <iostream>
#include "Int17Matrix3D.h"

Int17Matrix3D::Int17Matrix3D(int x, int y, int z) : width_(x), height_(y), depth_(z), array_(new int32_t[kNumLenght_ * x * y * z]){}

Int17Matrix3D::Int17Matrix3D(const Int17Matrix3D& other) : width_(other.width_), height_(other.height_), depth_(other.depth_), array_(new int32_t[kNumLenght_ * width_ * height_ * depth_]) {
    copy(array_, other.array_, kNumLenght_ * width_ * height_ * depth_);
}
Int17Matrix3D::~Int17Matrix3D() { delete[] array_; }

Int17Matrix3D& Int17Matrix3D::operator=(const Int17Matrix3D& other) {
  if (this != &other) {
    delete[] array_;
    width_ = other.width_;
    height_ = other.height_;
    depth_ = other.depth_;
    current_index_ = other.current_index_;
    max_index_ = other.max_index_;
    current_x_ = other.current_x_; 
    current_y_ = other.current_y_;
    current_z_ = other.current_z_;
    array_ = new int32_t[kNumLenght_ * width_ * height_ * depth_];
    copy(array_, other.array_, kNumLenght_ * width_ * height_ * depth_);
  }
  return *this;
}

Int17Matrix3D Int17Matrix3D::make_array(int x, int y, int z) {
  return Int17Matrix3D(x, y, z);
}

Int17Matrix3D& Int17Matrix3D::operator=(int32_t value) {
  int first_bit_index = current_index_ * kNumLenght_;

  for (int i = 0; i < kNumLenght_; ++i) {
    if (value & (1 << i)) {
      SetBit(array_, first_bit_index + i);
    } else {
      ClearBit(array_, first_bit_index + i);
    }
  }
  return *this;
}

void Int17Matrix3D::copy(int32_t* array1, const int32_t* array2, int size) {
  for (int i = 0; i < size; ++i) {
    array1[i] = array2[i];
  }
}

void Int17Matrix3D::SetValueAtCurrentIndex(int32_t value) {
    (*this)[current_x_][current_y_][current_z_] = value;
}

bool Int17Matrix3D::TakeBit(const int32_t* value, uint32_t bit_position) const {
  int array_index = bit_position / 32;
  int bit_index = bit_position % 32;
  return ((value[array_index] >> bit_index) & 1) != 0;
}

Int17Matrix3D& Int17Matrix3D::ClearBit(int32_t* value, int32_t bit_position) {
  value[bit_position / 32] &= ~(1 << (bit_position % 32));
  return *this;
}

Int17Matrix3D& Int17Matrix3D::SetBit(int32_t* value, int32_t bit_position) {
  value[bit_position / 32] |= (1 << (bit_position % 32));
  return *this;
}

int Int17Matrix3D::GetIndex(int x, int y, int z) const {
  return x + y * (width_ * kNumLenght_) + z * (width_ * height_ * kNumLenght_);
}

int32_t Int17Matrix3D::ToDecimal(const int32_t* array_, int32_t current_index_) const {
  int first_bit_index = current_index_ * kNumLenght_;
  int32_t decimal_value = 0;
  int32_t exp = 1;

  for (int i = 0; i < kNumLenght_; ++i) {
    if (TakeBit(array_, first_bit_index + i)) {
      decimal_value += exp;
    }
    exp <<= 1;
  }

  return decimal_value;
}

Int17Matrix3D Int17Matrix3D::operator+(const Int17Matrix3D& other) {
  if (this->width_ != other.width_ || this->height_ != other.height_ || this->depth_ != other.depth_) {
    throw std::out_of_range("Arrays must be with the same size");
  }

  Int17Matrix3D result(this->width_, this->height_, this->depth_);

  for (int z = 0; z < this->depth_; ++z) {
    for (int y = 0; y < this->height_; ++y) {
      for (int x = 0; x < this->width_; ++x) {
        int index = this->GetIndex(x, y, z);
        result[x][y][z] = this->ToDecimal(this->array_, index) + other.ToDecimal(other.array_, index);
      }
    }
  }
  return result;
}

Int17Matrix3D Int17Matrix3D::operator-(const Int17Matrix3D& other) {
  if (this->width_ != other.width_ || this->height_ != other.height_ || this->depth_ != other.depth_) {
    throw std::out_of_range("Arrays must be with the same size");
  }

  Int17Matrix3D result(this->width_, this->height_, this->depth_);

  for (int z = 0; z < this->depth_; ++z) {
    for (int y = 0; y < this->height_; ++y) {
      for (int x = 0; x < this->width_; ++x) {
        int index = this->GetIndex(x, y, z);
        result[x][y][z] = this->ToDecimal(this->array_, index) - other.ToDecimal(other.array_, index);
      }
    }
  }
  return result;
}

Int17Matrix3D Int17Matrix3D::operator*(int32_t mult) {
  Int17Matrix3D result(this->width_, this->height_, this->depth_);

  for (int z = 0; z < this->depth_; ++z) {
    for (int y = 0; y < this->height_; ++y) {
      for (int x = 0; x < this->width_; ++x) {
        int index = this->GetIndex(x, y, z);
        result[x][y][z] = this->ToDecimal(this->array_, index) * mult;
      }
    }
  }
  return result;
}

bool operator==(const Int17Matrix3D& lhs, const Int17Matrix3D& rhs) {
  return lhs.ToDecimal(lhs.array_, lhs.current_index_) == rhs.ToDecimal(rhs.array_, rhs.current_index_);
}

bool operator!=(const Int17Matrix3D& lhs, const Int17Matrix3D& rhs) {
  return !(lhs == rhs);
}

std::ostream& operator<<(std::ostream& stream, const Int17Matrix3D& matrix) {
  int32_t value = matrix.ToDecimal(matrix.array_, matrix.current_index_);
  stream << value;
  return stream;
}

std::istream& operator>>(std::istream& stream, Int17Matrix3D& array) {
  int32_t value;
  stream >> value;

  if (!stream) return stream;

  array.SetValueAtCurrentIndex(value);

  return stream;
}

Int17Matrix3D::Proxy2D Int17Matrix3D::operator[](int x) {
  if (x < 0 || x >= this->width_) {
        throw std::out_of_range("Index out of range in y-dimension");
    }
  return Proxy2D(*this, x);
}

Int17Matrix3D::Proxy1D Int17Matrix3D::Proxy2D::operator[](int y) {
    if (y < 0 || y >= parentMatrix_.height_) {
        throw std::out_of_range("Index out of range in y-dimension");
    }
    return Proxy1D(parentMatrix_, x_, y);
}


void Int17Matrix3D::SetValueAtIndex(int x, int y, int z, int32_t value) {
  int index = GetIndex(x, y, z);
  int bit_offset = index * kNumLenght_;

    // Clear previous value
  for (int bit = 0; bit < kNumLenght_; ++bit) {
    ClearBit(array_, bit_offset + bit);
    }

    // Set new value
    for (int bit = 0; bit < kNumLenght_; ++bit) {
      if (value & (1 << bit)) {
      SetBit(array_, bit_offset + bit);
    }
  }
}

int32_t Int17Matrix3D::GetValueAtIndex(int x, int y, int z) const {
  int index = GetIndex(x, y, z);
  return ToDecimal(array_, index * kNumLenght_);
}



