TEST(Int17Matrix3DTest, Addition_DifferentSize) {
  Int17Matrix3D arr1(1, 1, 1);
  Int17Matrix3D arr2(1, 1, 2);
  arr1[0][0][0] = 1;
  arr2[0][0][0] = 2;
  ASSERT_THROW(Int17Matrix3D arr3 = arr1 + arr2, std::out_of_range);
}

